// Font atlas geometry. The SDF atlas is a 512×192 R8 image laid out as
// 16 columns × 6 rows of 32×32-pixel glyphs (each 8×8 cell is upscaled 4×).
// These constants are a contract between atlas generation and every caller
// that computes UV coordinates for a glyph — keep in sync.
constexpr int kFontGridCols = 16;
constexpr int kFontGridRows = 6;
constexpr int kFontGlyphPx  = 32;
constexpr int kFontAtlasW   = kFontGridCols * kFontGlyphPx; // 512
constexpr int kFontAtlasH   = kFontGridRows * kFontGlyphPx; // 192

// Generate the SDF atlas. Same algorithm as the GL TextRenderer: upscale
// each 8×8 glyph to 32×32, then for each output pixel compute the distance
// to the nearest pixel of opposite polarity inside a ±6-pixel search box.
// `out` is resized to kFontAtlasW * kFontAtlasH (one byte per pixel, 0..255).
inline void generateUiFontAtlas(std::vector<uint8_t>& out) {
	constexpr int SCALE = 4;
	constexpr int SEARCH = 6;
	constexpr float SPREAD = static_cast<float>(SEARCH);

	std::vector<uint8_t> bitmap(kFontAtlasW * kFontAtlasH, 0);
	for (int ch = 0; ch < 96; ch++) {
		int gx = (ch % kFontGridCols) * kFontGlyphPx;
		int gy = (ch / kFontGridCols) * kFontGlyphPx;
		for (int row = 0; row < 8; row++) {
			uint8_t bits = FONT_8X8[ch][row];
			for (int col = 0; col < 8; col++) {
				if (bits & (1 << col)) {
					for (int sy = 0; sy < SCALE; sy++)
						for (int sx = 0; sx < SCALE; sx++)
							bitmap[(gy + row * SCALE + sy) * kFontAtlasW
								+ (gx + col * SCALE + sx)] = 1;
				}
			}
		}
	}

	out.assign(kFontAtlasW * kFontAtlasH, 0);
	for (int y = 0; y < kFontAtlasH; y++) {
		for (int x = 0; x < kFontAtlasW; x++) {
			bool inside = bitmap[y * kFontAtlasW + x] != 0;
			float minDistSq = SPREAD * SPREAD;
			for (int dy = -SEARCH; dy <= SEARCH; dy++) {
				int ny = y + dy;
				if (ny < 0 || ny >= kFontAtlasH) continue;
				for (int dx = -SEARCH; dx <= SEARCH; dx++) {
					int nx = x + dx;
					if (nx < 0 || nx >= kFontAtlasW) continue;
					bool other = bitmap[ny * kFontAtlasW + nx] != 0;
					if (other != inside) {
						float dsq = static_cast<float>(dx * dx + dy * dy);
						if (dsq < minDistSq) minDistSq = dsq;
					}
				}
			}
			float dist = std::sqrt(minDistSq);
			float val = inside ? (0.5f + 0.5f * dist / SPREAD)
			                   : (0.5f - 0.5f * dist / SPREAD);
			out[y * kFontAtlasW + x] =
				static_cast<uint8_t>(std::clamp(val, 0.0f, 1.0f) * 255.0f);
		}
	}
}

